import SwiftUI

final class ProfileViewModel: ObservableObject {
  @Published var name = ""

  func load() {
    Task.detached {
      self.name = await fetchName()
    }
  }
}

import SwiftUI

@MainActor
final class ProfileViewModel: ObservableObject {
  @Published var name = ""

  func load() {
    Task {
      let value = await fetchName()
      self.name = value
    }
  }
}
